.darma-loader-darma-custom-344 {color: var(--loader-color, #e11d48);
  display: inline-grid;
  width: 80px;
  aspect-ratio: 1;
}.darma-loader-darma-custom-344:before,.darma-loader-darma-custom-344:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
}.darma-loader-darma-custom-344:before {margin: 25%;
  background: repeating-conic-gradient(var(--loader-color, #e11d48) 0 60deg,var(--loader-secondary-color, #fb7185) 0 120deg);
  transform: rotate(0turn) translate(50%) rotate(0turn);
  animation: darma-loader-darma-custom-344-l1 3s linear infinite;
}.darma-loader-darma-custom-344:after {padding: 10%;
  margin: -10%;
  background: repeating-conic-gradient(from -15deg,var(--loader-color, #e11d48) 0 30deg,var(--loader-secondary-color, #fb7185) 0 60deg);
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
}@keyframes darma-loader-darma-custom-344-l1 {to{transform: rotate(1turn) translate(50%) rotate(-2turn)}}

